class Graph:
    def __init__(self, n, edges):
        self.n = n
        self.edges = [list(e) for e in edges]

    def addEdge(self, edge):
        self.edges.append(list(edge))

    def shortestPath(self, node1, node2):
        INF = float('inf')
        dist = [INF] * self.n
        dist[node1] = 0
        for _ in range(self.n - 1):
            updated = False
            for f, t, c in self.edges:
                if dist[f] != INF and dist[f] + c < dist[t]:
                    dist[t] = dist[f] + c
                    updated = True
            if not updated:
                break
        return dist[node2] if dist[node2] != INF else -1

