        self.adj[f].append((t, c))

    def shortestPath(self, node1, node2):
        n = self.n
        INF = float('inf')
        dist = [INF] * n
        dist[node1] = 0
        visited = [False] * n
        for _ in range(n):
            u = -1
            best = INF
            for i in range(n):
                if not visited[i] and dist[i] < best:
                    best = dist[i]
                    u = i
            if u == -1:
                break
            visited[u] = True
            if u == node2:
                return dist[u]
            for v, w in self.adj[u]:
                if dist[u] + w < dist[v]:
                    dist[v] = dist[u] + w
        return dist[node2] if dist[node2] != INF else -1

