class Graph {
    constructor(n, edges) {
        this.n = n;
        this.adj = Array.from({ length: n }, () => []);
        for (const [f, t, c] of edges) {
            this.adj[f].push([t, c]);
        }
    }
    addEdge(edge) {
        const [f, t, c] = edge;
        this.adj[f].push([t, c]);
    }
    shortestPath(node1, node2) {
        const n = this.n;
        const INF = Infinity;
        const dist = new Array(n).fill(INF);
        dist[node1] = 0;
        const visited = new Array(n).fill(false);
        for (let iter = 0; iter < n; iter++) {
            let u = -1;
            let best = INF;
            for (let i = 0; i < n; i++) {
                if (!visited[i] && dist[i] < best) {
                    best = dist[i];
                    u = i;
                }
            }
            if (u === -1) break;
            visited[u] = true;
            if (u === node2) return dist[u];
            for (const [v, w] of this.adj[u]) {
                if (dist[u] + w < dist[v]) dist[v] = dist[u] + w;
            }
        }
        return dist[node2] === INF ? -1 : dist[node2];
    }
}
